#include <stdio.h>
#include <stdbool.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int A[100000];
        for (int i = 0; i < N; ++i) scanf("%d", &A[i]);
        bool first = true, any = false;
        for (int i = 0; i < N; ++i) {
            if ((i == 0 || A[i] > A[i-1]) && (i == N-1 || A[i] > A[i+1])) {
                if (!first) printf(" ");
                printf("%d", A[i]);
                first = false;
                any = true;
            }
        }
        if (!any) printf("-1");
        if (T) printf("\n");
    }
    return 0;
}

