const T = Number(data[idx++]);
let results = [];
for (let t = 0; t < T; ++t) {
  const N = Number(data[idx++]);
  const A = [];
  for (let i = 0; i < N; ++i) A.push(Number(data[idx++]));
  const peaks = [];
  for (let i = 0; i < N; ++i) {
    if ((i === 0 || A[i] > A[i-1]) && (i === N-1 || A[i] > A[i+1])) {
      peaks.push(A[i]);
    }
  }
  results.push(peaks.length ? peaks.join(' ') : '-1');
}
process.stdout.write(results.join('\n'));
